    "src": "package Main;\n\nimport Core.Output;\nimport Core.List;\n\nclass Point {\n    constructor(private int x, private int y) {}\n    function show(): string {\n        return \"({this.x}, {this.y})\";\n    }\n}\n\nfunction main(): void {\n    List<int> nums = [10, 20, 30];\n    int count = List.length(nums);\n    // → PHP count(); generic over the element type\n    Output.printLine(\"count = {count}\");\n    for (int n in nums) {\n        Output.printLine(\"n = {n}\");\n    }\n    List<List<int>> grid = [[1, 2], [3, 4]];\n    for (List<int> row in grid) {\n        for (int v in row) {\n            Output.printLine(\"v = {v}\");\n        }\n    }\n    List<Point> pts = [new Point(0, 0), new Point(1, 2)];\n    for (Point p in pts) {\n        Output.printLine(p.show());\n    }\n}\n"
