    "name": "collections-more",
    "src": "package Main;\n\nimport Core.Output;\nimport Core.List;\nimport Core.Map;\nimport Core.Set;\n\n// More collection queries (M4 stdlib breadth) — emptiness tests, flattening, predicate counting, and a\n// set→list conversion. Each maps to an idiomatic PHP array operation, byte-identical on both backends and PHP.\nfunction main(): void {\n    // List.isEmpty\n    Output.printLine(\"empty []   = {List.isEmpty(new List<int>())}\");\n    Output.printLine(\"empty [1,2] = {List.isEmpty([1, 2])}\");\n    // List.flatten — concatenate a list of lists.\n    List<int> flat = List.flatten([[1, 2], [3], [4, 5]]);\n    Output.printLine(\"flatten length = {List.length(flat)}, sum = {List.sum(flat)}\");\n    // List.count — how many elements satisfy a predicate.\n    int evens = List.count([1, 2, 3, 4, 5, 6], function(int x) => x % 2 == 0);\n    Output.printLine(\"evens = {evens}\");\n    // Map.isEmpty — directly, and after filtering everything out.\n    Map<string, int> ages = [\"ada\" => 36, \"alan\" => 41];\n    Map<string, int> over100 = Map.filter(ages, function(int v) => v > 100);\n    Output.printLine(\"ages empty = {Map.isEmpty(ages)}, filtered empty = {Map.isEmpty(over100)}\");\n    // Set.isEmpty + Set.toList (insertion order, deduplicated).\n    Set<int> s = Set.of([3, 1, 2, 1, 3]);\n    List<int> back = Set.toList(s);\n    Output.printLine(\n        \"set empty = {Set.isEmpty(s)}, toList length = {List.length(back)}, sum = {List.sum(back)}\"\n    );\n}\n"
