    "category": "guide",
    "name": "collections-query",
    "src": "// Core.List + Core.Map query natives (M-RT S7b) — the first *generic* stdlib natives. Their\n// signatures carry type parameters (`List.reverse(List<T>) -> List<T>`, `Map.keys(Map<K,V>) ->\n// List<K>`), inferred at the call site by the same unifier as a generic free function — no\n// monomorphization, the type params never reach a backend. Byte-identical on both backends and real PHP.\n//\n// Map keys here are plain (non-numeric) strings: PHP arrays coerce integer-like string keys and\n// bools to int keys, so `Map.keys` over such a map would render differently under PHP (KNOWN_ISSUES);\n// plain string keys are kept verbatim. Integer arithmetic only (PHP's float `/` never enters).\npackage Main;\n\nimport Core.Output;\nimport Core.List;\nimport Core.Map;\n\nfunction main(): void {\n    // --- Core.List: reverse (generic) + sum (concrete List<int> -> int) ---\n    var nums = [1, 2, 3, 4, 5];\n    var rev = List.reverse(nums);\n    var head = rev[0];\n    Output.printLine(\"sum        = {List.sum(nums)}\");\n    Output.printLine(\"reversed[0] = {head}\");\n    Output.printLine(\"sum(rev)   = {List.sum(rev)}\");\n    // append (generic) — a new list with one element added at the end (lists are immutable/COW).\n    var more = List.append(nums, 6);\n    Output.printLine(\"appended   = {List.length(more)} last={more[5]}\");\n    // contains (generic, PHP `in_array` strict) — membership over a scalar list.\n    Output.printLine(\"has 3      = {List.contains(nums, 3)}\");\n    Output.printLine(\"has 9      = {List.contains(nums, 9)}\");\n    var words = [\"alpha\", \"beta\"];\n    var hasBeta = List.contains(words, \"beta\");\n    Output.printLine(\"has beta   = {hasBeta}\");\n    // --- Core.Map: size / has / keys / values, insertion-ordered ---\n    var ages = [\"alice\" => 30, \"bob\" => 25, \"carol\" => 41];\n    var hasBob = Map.has(ages, \"bob\");\n    var hasDave = Map.has(ages, \"dave\");\n    Output.printLine(\"size       = {Map.size(ages)}\");\n    Output.printLine(\"has bob    = {hasBob}\");\n    Output.printLine(\"has dave   = {hasDave}\");\n    // keys() preserves insertion order; index back into the map by each key.\n    for (string name in Map.keys(ages)) {\n        var age = ages[name];\n        Output.printLine(\"{name} -> {age}\");\n    }\n    // values() feeds straight into List.sum.\n    var total = List.sum(Map.values(ages));\n    Output.printLine(\"total age  = {total}\");\n}\n"
